  '[{"title":"Faster decision-making","description":"Teams get one clear source for daily and strategic performance.","order":0},{"title":"Improved visibility","description":"Leadership can see trends, gaps, and priorities without manual reporting delays.","order":1},{"title":"Better planning","description":"Forecasting and KPI tracking support proactive business moves.","order":2},{"title":"Reduced reporting effort","description":"Automated dashboards cut repetitive spreadsheet work.","order":3}]'::jsonb,
  '[{"title":"Practical solutions","description":"We build dashboards around real business questions, not vanity metrics.","order":0},{"title":"Business-focused approach","description":"Every KPI is tied to decisions and outcomes.","order":1},{"title":"Scalable systems","description":"Reporting structures can grow as data and departments expand.","order":2},{"title":"Ongoing support","description":"We help maintain, improve, and extend your analytics setup.","order":3}]'::jsonb,
  '[{"stepNumber":1,"title":"Discovery","description":"Understand business goals, data sources, and reporting pain points.","order":0},{"stepNumber":2,"title":"Strategy","description":"Define KPIs, dashboard structure, and decision workflows.","order":1},{"stepNumber":3,"title":"Design / Planning","description":"Map data models, visuals, and user journeys.","order":2},{"stepNumber":4,"title":"Development / Implementation","description":"Build dashboards, pipelines, measures, and reports.","order":3},{"stepNumber":5,"title":"Testing","description":"Validate data quality, calculations, and usability.","order":4},{"stepNumber":6,"title":"Support & Optimization","description":"Improve reporting performance and add new business views over time.","order":5}]'::jsonb,
